import React from 'react';

import Lottie from 'lottie-react-native';
import { useTheme } from 'styled-components/native';

import theme from '../../../styles/theme';

import LoadingJSON from '../../../assets/animations/Loadings/loading-core.json';
import normalize from '../../constants/normalize';
import { Box } from '../Box';
import { PropsLoadingCore } from './Models';

function LoadingCore({ mb, ml, mr, mt, testID, contrast }: PropsLoadingCore) {
  const { colors } = useTheme() || theme;
  return (
    <Box testID={testID} mb={mb} ml={ml} mr={mr} mt={mt}>
      <Lottie
        source={LoadingJSON}
        autoPlay
        loop
        style={{
          width: normalize(20),
          height: normalize(20),
        }}
        colorFilters={[
          {
            keypath: 'Loading',
            color: contrast ? colors.INTENSE_COLOR_01 : colors.BRAND_BASE_01,
          },
          {
            keypath: 'Fundo',
            color: contrast ? colors.INTENSE_COLOR_05 : colors.INTENSE_COLOR_01,
          },
        ]}
      />
    </Box>
  );
}

export default LoadingCore;

